query:
SELECT COUNT(*) as team_count FROM mlb_teams;
SELECT league, division, COUNT(*) as count FROM mlb_teams GROUP BY league, division ORDER BY league, division;
SELECT COUNT(*) as player_count FROM mlb_players;
SELECT COUNT(*) as active_count FROM mlb_players WHERE isActive = 1;
SELECT COUNT(*) as inactive_count FROM mlb_players WHERE isActive = 0;
SELECT p.name, p.position, p.bats, p.throws, p.currentTeamBrAbbrev, p.isActive
FROM mlb_players p ORDER BY p.name LIMIT 10;

